export class Search extends HeyApiClient {
    /**
     * Multi Field
     *
     * Advanced multi-field matching endpoint that finds the best matching items from a list based on multiple search criteria.
     *
     * This endpoint performs sophisticated text matching across multiple fields of items, supporting different search algorithms,
     * text transformations, and weighted scoring to provide highly accurate matching results.
     *
     * ## How It Works
     *
     * The endpoint evaluates each item against multiple search fields, where each field can have:
     * - Different search algorithms (exact, fuzzy, or GPT-based semantic matching)
     * - Custom text transformations applied before matching
     * - Individual weighting (ponderation) that affects the final score
     * - Optional text replacement rules
     *
     * The final score for each item is calculated by:
     * 1. Computing individual field scores using the specified search type
     * 2. Applying text transformations and replacements to search values
     * 3. Multiplying each field score by its ponderation weight
     * 4. Summing all weighted scores to get the final item score
     * 5. Returning the top N items sorted by score (descending)
     *
     * ## Weighting System (Ponderation)
     *
     * Each field has a ponderation value (0 < ponderation ≤ 1) that determines its importance:
     * - Higher ponderation = more influence on final score
     * - All field ponderations must sum to exactly 1.0
     * - Example: If field A has ponderation 0.7 and field B has 0.3, field A has more than twice the influence
     */
    public multiField<ThrowOnError extends boolean = false>(options: Options<SearchMultiFieldData, ThrowOnError>) {
        return (options.client ?? this.client).post<SearchMultiFieldResponses, SearchMultiFieldErrors, ThrowOnError>({
            requestValidator: async (data) => await z.object({
                body: zSearchMultiFieldBody,
                path: z.never().optional(),
                query: z.never().optional()
            }).parseAsync(data),
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/core/search/multi-field',
            ...options,
            headers: {
                'Content-Type': 'application/json',
                ...options.headers
            }
        });
    }
}

